import * as React from "react"
import type { BaseFormFieldProps } from "@/registry/lib/base-form-props"

import { cn } from "@/lib/utils"
import { Switch } from "@/components/ui/switch"

export interface FormSwitchProps
  extends Omit<BaseFormFieldProps, 'value' | 'onChange' | 'onBlur' | 'name' | 'ref' | 'id' | 'schema' | 'record'>,
  Omit<React.ComponentPropsWithoutRef<typeof Switch>, "onChange"> {
  /**
   * 当前值
   */
  checked?: boolean
  /**
   * 默认值
   */
  defaultChecked?: boolean
  /**
   * 是否禁用
   */
  disabled?: boolean
  /**
   * 自动聚焦
   */
  autoFocus?: boolean
  /**
   * 值变化回调
   */
  onChange?: (checked: boolean) => void
}

const FormSwitch = React.forwardRef<HTMLButtonElement, FormSwitchProps>(
  (
    {
      className,
      checked: controlledChecked,
      defaultChecked = false,
      disabled = false,
      autoFocus = false,
      onChange,
      ...props
    },
    ref
  ) => {
    const [internalChecked, setInternalChecked] = React.useState(defaultChecked)
    const isControlled = controlledChecked !== undefined
    const checked = isControlled ? controlledChecked : internalChecked

    const handleChange = React.useCallback(
      (newChecked: boolean) => {
        if (!isControlled) {
          setInternalChecked(newChecked)
        }
        onChange?.(newChecked)
      },
      [isControlled, onChange]
    )

    return (
      <div className="widget-switch">
        <Switch
          ref={ref}
          className={cn(
            className
          )}
          checked={checked}
          onCheckedChange={handleChange}
          disabled={disabled}
          autoFocus={autoFocus}
          type="button"
          {...props}
        />
      </div>
    )
  }
)
FormSwitch.displayName = "FormSwitch"

export { FormSwitch }

import type { Ref } from 'react'

/** 所有通过 FormField 使用的组件共享的 props */
export interface BaseFormFieldProps {
  /** 当前值（react-hook-form） */
  value?: any
  /** 值变更回调（react-hook-form） */
  onChange?: (value: any) => void
  /** 失焦回调（react-hook-form） */
  onBlur?: () => void
  /** 字段名（react-hook-form） */
  name?: string
  /** ref（react-hook-form） */
  ref?: Ref<any>
  /** 字段 ID（FormField 生成） */
  id?: string
  /** 表单 schema */
  schema?: Record<string, any>
  /** 表单记录数据 */
  record?: any
}

/** 选项类型 */
export interface FormOption {
  value: string | number
  label?: string
  disabled?: boolean
}
